'use client';
import { useEffect, useState, Suspense } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { Check, Calendar, Mail, ArrowRight } from 'lucide-react';
import Link from 'next/link';

function RequestedContent() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const projectId = searchParams.get('id');
    const [email, setEmail] = useState<string>('');

    useEffect(() => {
        // Optionally fetch project details to show email
        if (projectId) {
            // Store projectId in localStorage for later access
            localStorage.setItem('concierge-project-id', projectId);
        } else {
            // If no ID, redirect back
            router.push('/concierge/request');
        }
    }, [projectId, router]);

    return (
        <div className="min-h-screen bg-gradient-to-br from-sage/5 via-ivory to-terracotta/5 flex items-center justify-center p-6">
            <div className="max-w-2xl w-full">
                {/* Success Icon */}
                <div className="flex justify-center mb-8">
                    <div className="relative">
                        <div className="w-24 h-24 bg-gradient-to-br from-sage to-sage/80 rounded-full flex items-center justify-center shadow-xl">
                            <Check size={48} className="text-ivory" strokeWidth={3} />
                        </div>
                        <div className="absolute -top-2 -right-2 w-8 h-8 bg-terracotta rounded-full flex items-center justify-center animate-bounce">
                            <span className="text-ivory text-xl">✓</span>
                        </div>
                    </div>
                </div>

                {/* Main Content */}
                <div className="bg-white rounded-2xl border border-sand/30 shadow-lg p-8 md:p-12 text-center">
                    <h1 className="font-serif text-4xl md:text-5xl text-charcoal mb-4">
                        Request Received
                    </h1>
                    <p className="text-lg text-charcoal/70 mb-8 leading-relaxed">
                        Thank you for your interest in our Concierge service. We'll contact you within 24 hours to schedule your first call.
                    </p>

                    {/* What happens next */}
                    <div className="text-left bg-gradient-to-br from-sage/5 to-terracotta/5 rounded-xl p-6 mb-8">
                        <h2 className="font-semibold text-charcoal mb-4 flex items-center gap-2">
                            <Calendar size={20} className="text-sage" />
                            What happens next
                        </h2>
                        <div className="space-y-3 text-sm text-charcoal/70">
                            <p className="flex items-start gap-3">
                                <span className="text-sage mt-1">1.</span>
                                <span>We'll email you to schedule a convenient time for your free consultation call</span>
                            </p>
                            <p className="flex items-start gap-3">
                                <span className="text-sage mt-1">2.</span>
                                <span>During the call, we'll discuss your needs, materials, and answer all your questions</span>
                            </p>
                            <p className="flex items-start gap-3">
                                <span className="text-sage mt-1">3.</span>
                                <span>If you decide to proceed, we'll create your dedicated space where you can share materials</span>
                            </p>
                        </div>
                    </div>

                    {/* Check email reminder */}
                    <div className="flex items-center justify-center gap-2 text-sm text-charcoal/60 mb-8">
                        <Mail size={16} />
                        <span>Please check your email inbox (and spam folder)</span>
                    </div>

                    {/* Actions */}
                    <div className="flex flex-col sm:flex-row gap-4">
                        <Link
                            href="/choice"
                            className="flex-1 py-3 border-2 border-sand/40 hover:bg-sand/10 text-charcoal rounded-xl font-medium transition-all text-center"
                        >
                            Back to Home
                        </Link>
                        <Link
                            href="mailto:contact@legacyvault.com"
                            className="flex-1 py-3 bg-sage hover:bg-sage/90 text-ivory rounded-xl font-medium transition-all flex items-center justify-center gap-2"
                        >
                            Contact Us Directly
                            <ArrowRight size={18} />
                        </Link>
                    </div>
                </div>

                {/* Footer note */}
                <p className="text-center text-sm text-charcoal/50 mt-8">
                    Your request ID: <span className="font-mono text-charcoal/70">{projectId?.slice(0, 8)}</span>
                </p>
            </div>
        </div>
    );
}

export default function RequestedPage() {
    return (
        <Suspense fallback={
            <div className="min-h-screen bg-ivory flex items-center justify-center">
                <div className="w-16 h-16 border-4 border-sage/30 border-t-sage rounded-full animate-spin" />
            </div>
        }>
            <RequestedContent />
        </Suspense>
    );
}